func ffmpegListContains(output, name string) bool {
	for _, line := range strings.Split(output, "\n") {
		fields := strings.Fields(line)
		if len(fields) >= 2 && fields[1] == name {
			return true
		}
	}
	return strings.Contains(output, " "+name+" ")
}

func ffprobeDuration(ffprobePath, path string) (float64, error) {
	out, err := runCommandCapture("", ffprobePath, "-v", "error", "-show_entries", "format=duration", "-of", "default=noprint_wrappers=1:nokey=1", path)
	if err != nil {
		return 0, err
	}
	seconds, err := strconv.ParseFloat(strings.TrimSpace(out), 64)
	if err != nil {
		return 0, fmt.Errorf("parsing ffprobe duration for %s: %w", path, err)
	}
	return seconds, nil
}

func runPodcastMix(tools ffmpegTools, outDir string, items []podcastMixItem, targetLUFS float64, emitWAV bool) (podcastMixResult, error) {
	if len(items) == 0 {
		return podcastMixResult{}, fmt.Errorf("no audio items to mix")
	}
	for i := range items {
		dur, err := ffprobeDuration(tools.FFprobe, items[i].Path)
		if err != nil {
			return podcastMixResult{}, fmt.Errorf("probing %s: %w", items[i].Path, err)
		}
		items[i].DurationSeconds = dur
	}
	workDir := filepath.Join(outDir, "mix")
	if err := os.MkdirAll(workDir, 0o755); err != nil {
		return podcastMixResult{}, err
	}
	filterPath := filepath.Join(workDir, "assembly.ffgraph")
	filterGraph := buildPodcastFilterGraph(items)
	if err := os.WriteFile(filterPath, []byte(filterGraph), 0o644); err != nil {
		return podcastMixResult{}, err
	}
	masterPath := filepath.Join(workDir, "master.wav")
	renderArgs := []string{"-y", "-hide_banner"}
	for _, item := range items {
		renderArgs = append(renderArgs, "-i", item.Path)
		if item.BedPath != "" {
			renderArgs = append(renderArgs, "-i", item.BedPath)
		}
	}
	renderArgs = append(renderArgs, "-filter_complex_script", filterPath, "-map", "[mixout]", "-ar", "44100", "-ac", "2", "-sample_fmt", "s16", masterPath)
	renderCmd := formatCommand(tools.FFmpeg, renderArgs)
	if _, err := runCommandCapture("", tools.FFmpeg, renderArgs...); err != nil {
		return podcastMixResult{}, fmt.Errorf("ffmpeg assembly failed: %w", err)
	}
	measurement, measureCmd, err := measureLoudnorm(tools.FFmpeg, masterPath, targetLUFS)
	if err != nil {
		return podcastMixResult{}, err
	}
	mp3Path := filepath.Join(outDir, "episode.mp3")
	applyArgs := loudnormApplyArgs(masterPath, mp3Path, targetLUFS, measurement, true)
	applyCmd := formatCommand(tools.FFmpeg, applyArgs)
	if _, err := runCommandCapture("", tools.FFmpeg, applyArgs...); err != nil {
		return podcastMixResult{}, fmt.Errorf("ffmpeg loudnorm apply failed: %w", err)
	}
	result := podcastMixResult{
		MasterPath:      masterPath,
		EpisodeMP3Path:  mp3Path,
		FilterGraphPath: filterPath,
		FilterGraph:     filterGraph,
		Loudnorm:        measurement,
		Commands: []string{
			renderCmd,
			measureCmd,
			applyCmd,
		},
	}
	if emitWAV {
		wavPath := filepath.Join(outDir, "episode.wav")
		wavArgs := loudnormApplyArgs(masterPath, wavPath, targetLUFS, measurement, false)
		result.Commands = append(result.Commands, formatCommand(tools.FFmpeg, wavArgs))
		if _, err := runCommandCapture("", tools.FFmpeg, wavArgs...); err != nil {
			return podcastMixResult{}, fmt.Errorf("ffmpeg wav loudnorm apply failed: %w", err)
		}
		result.EpisodeWAVPath = wavPath
	}
	return result, nil
}

func buildPodcastFilterGraph(items []podcastMixItem) string {
	var b strings.Builder
	inputIndex := 0
	clipLabels := make([]string, 0, len(items))
	for i, item := range items {
		voiceLabel := fmt.Sprintf("n%d", i)
		fmt.Fprintf(&b, "[%d:a]aresample=%d,aformat=sample_fmts=fltp:channel_layouts=stereo[%s];\n", inputIndex, podcastSampleRate, voiceLabel)
		inputIndex++
		clipLabel := fmt.Sprintf("clip%d", i)
		if item.BedPath != "" {
			bedNorm := fmt.Sprintf("bedn%d", i)
			bedSpan := fmt.Sprintf("bedspan%d", i)
			ducked := fmt.Sprintf("ducked%d", i)
			spanSeconds := math.Max(item.DurationSeconds, 0.1)
			spanSamples := int(math.Ceil(spanSeconds * podcastSampleRate))
			fmt.Fprintf(&b, "[%d:a]aresample=%d,aformat=sample_fmts=fltp:channel_layouts=stereo[%s];\n", inputIndex, podcastSampleRate, bedNorm)
			inputIndex++
			fmt.Fprintf(&b, "[%s]aloop=loop=-1:size=%d,atrim=0:%.3f,asetpts=N/SR/TB[%s];\n", bedNorm, spanSamples, spanSeconds, bedSpan)
			fmt.Fprintf(&b, "[%s][%s]sidechaincompress=threshold=0.03:ratio=8:attack=20:release=300:makeup=1[%s];\n", bedSpan, voiceLabel, ducked)
			fmt.Fprintf(&b, "[%s][%s]amix=inputs=2:normalize=0,alimiter=limit=0.95[%s];\n", ducked, voiceLabel, clipLabel)
		} else {
			switch item.Kind {
			case "intro":
				fmt.Fprintf(&b, "[%s]afade=t=in:d=0.5[%s];\n", voiceLabel, clipLabel)
			case "outro":
				fmt.Fprintf(&b, "[%s]afade=t=out:st=%.3f:d=1[%s];\n", voiceLabel, math.Max(item.DurationSeconds-1, 0), clipLabel)
			default:
				fmt.Fprintf(&b, "[%s]anull[%s];\n", voiceLabel, clipLabel)
			}
		}
		clipLabels = append(clipLabels, clipLabel)
	}
	current := clipLabels[0]
	for i := 1; i < len(clipLabels); i++ {
		next := clipLabels[i]
		out := fmt.Sprintf("seq%d", i)
		prevKind := items[i-1].Kind
		nextKind := items[i].Kind
		if (prevKind == "intro" && nextKind == "voice") || (prevKind == "voice" && nextKind == "outro") {
			fmt.Fprintf(&b, "[%s][%s]acrossfade=d=1.0:c1=tri:c2=tri[%s];\n", current, next, out)
		} else {
			fmt.Fprintf(&b, "[%s][%s]concat=n=2:v=0:a=1[%s];\n", current, next, out)
		}
		current = out
	}
	fmt.Fprintf(&b, "[%s]alimiter=limit=0.95[mixout]\n", current)
	return b.String()
}

func measureLoudnorm(ffmpegPath, input string, targetLUFS float64) (loudnormMeasurement, string, error) {
	return measureLoudnormWithPeak(ffmpegPath, input, targetLUFS, -1.5)
}

func measureLoudnormWithPeak(ffmpegPath, input string, targetLUFS, truePeak float64) (loudnormMeasurement, string, error) {
	args := []string{"-hide_banner", "-i", input, "-af", loudnormMeasureFilter(targetLUFS, truePeak), "-f", "null", "-"}
	cmdText := formatCommand(ffmpegPath, args)
	out, err := runCommandCapture("", ffmpegPath, args...)
	if err != nil {
		return loudnormMeasurement{}, cmdText, fmt.Errorf("ffmpeg loudnorm measure failed: %w", err)
	}
	measurement, err := parseLoudnormMeasurement(out)
	if err != nil {
		return loudnormMeasurement{}, cmdText, err
	}
	return measurement, cmdText, nil
}

func loudnormMeasureFilter(targetLUFS, truePeak float64) string {
	return fmt.Sprintf("loudnorm=I=%.1f:TP=%.1f:LRA=11:print_format=json", targetLUFS, truePeak)
}

func loudnormApplyArgs(input, output string, targetLUFS float64, m loudnormMeasurement, mp3 bool) []string {
	return loudnormApplyArgsWithPeak(input, output, targetLUFS, -1.5, m, mp3)
}

func loudnormApplyArgsWithPeak(input, output string, targetLUFS, truePeak float64, m loudnormMeasurement, mp3 bool) []string {
	filter := fmt.Sprintf("loudnorm=I=%.1f:TP=%.1f:LRA=11:measured_I=%s:measured_TP=%s:measured_LRA=%s:measured_thresh=%s:offset=%s:linear=true",
		targetLUFS, truePeak, m.InputI, m.InputTP, m.InputLRA, m.InputThresh, m.TargetOffset)
	args := []string{"-y", "-hide_banner", "-i", input, "-af", filter, "-ar", "44100", "-ac", "2"}
	if mp3 {
		args = append(args, "-c:a", "libmp3lame", "-b:a", "192k")
	}
	args = append(args, output)
	return args
}

func parseLoudnormMeasurement(output string) (loudnormMeasurement, error) {
	start := strings.LastIndex(output, "{")
	end := strings.LastIndex(output, "}")
	if start < 0 || end <= start {
		return loudnormMeasurement{}, fmt.Errorf("ffmpeg loudnorm output did not include JSON measurement")
	}
	var measurement loudnormMeasurement
	if err := json.Unmarshal([]byte(output[start:end+1]), &measurement); err != nil {
		return loudnormMeasurement{}, fmt.Errorf("parsing loudnorm measurement: %w", err)
	}
	if measurement.InputI == "" || measurement.InputTP == "" || measurement.InputLRA == "" || measurement.InputThresh == "" || measurement.TargetOffset == "" {
		return loudnormMeasurement{}, fmt.Errorf("loudnorm measurement missing required fields")
	}
	return measurement, nil
}

func runCommandCapture(dir, name string, args ...string) (string, error) {
	cmd := exec.Command(name, args...)
	cmd.Dir = dir
	var combined bytes.Buffer
	cmd.Stdout = &combined
	cmd.Stderr = &combined
	if err := cmd.Run(); err != nil {
		return combined.String(), fmt.Errorf("%s\n%s", err, tailString(combined.String(), 4000))
	}
	return combined.String(), nil
}

func formatCommand(name string, args []string) string {
	parts := append([]string{name}, args...)
	return strings.Join(parts, " ")
}

func tailString(s string, max int) string {
	if len(s) <= max {
		return s
	}
	return s[len(s)-max:]
}
